#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

class SecureCICD {
  constructor() {
    this.allowedCommands = new Set([
      'npm',
      'node',
      'git',
      'tar',
      'gzip'
    ]);
    
    this.requiredEnvVars = [
      'DEPLOY_TARGET',
      'DEPLOY_KEY_PATH',
      'DEPLOY_USER',
      'DEPLOY_HOST',
      'NODE_ENV'
    ];
    
    this.logFile = path.join(process.cwd(), 'deploy.log');
    this.sbomFile = path.join(process.cwd(), 'sbom.json');
  }

  sanitizeLog(message) {
    const sensitivePatterns = [
      /password[=:]\s*\S+/gi,
      /token[=:]\s*\S+/gi,
      /key[=:]\s*\S+/gi,
      /secret[=:]\s*\S+/gi,
      /api[_-]?key[=:]\s*\S+/gi,
      /Bearer\s+\S+/gi,
      /ssh-rsa\s+\S+/gi
    ];

    let sanitized = message;
    sensitivePatterns.forEach(pattern => {
      sanitized = sanitized.replace(pattern, '[REDACTED]');
    });
    
    return sanitized;
  }

  log(message, level = 'INFO') {
    const timestamp = new Date().toISOString();
    const sanitized = this.sanitizeLog(message);
    const logEntry = `[${timestamp}] [${level}] ${sanitized}\n`;
    
    fs.appendFileSync(this.logFile, logEntry);
    console.log(sanitized);
  }

  validateEnvironment() {
    this.log('Validating environment variables');
    
    const missing = this.requiredEnvVars.filter(varName => !process.env[varName]);
    
    if (missing.length > 0) {
      throw new Error(`Missing required environment variables: ${missing.join(', ')}`);
    }

    const allowedTargets = ['staging', 'production'];
    if (!allowedTargets.includes(process.env.DEPLOY_TARGET)) {
      throw new Error(`Invalid DEPLOY_TARGET. Must be one of: ${allowedTargets.join(', ')}`);
    }

    const allowedEnvs = ['production', 'staging'];
    if (!allowedEnvs.includes(process.env.NODE_ENV)) {
      throw new Error(`Invalid NODE_ENV. Must be one of: ${allowedEnvs.join(', ')}`);
    }

    const keyPath = process.env.DEPLOY_KEY_PATH;
    if (!fs.existsSync(keyPath)) {
      throw new Error('Deploy key file not found');
    }

    const stats = fs.statSync(keyPath);
    const mode = stats.mode & parseInt('777', 8);
    if (mode !== parseInt('600', 8) && mode !== parseInt('400', 8)) {
      throw new Error('Deploy key file has insecure permissions. Must be 600 or 400');
    }

    const hostPattern = /^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
    if (!hostPattern.test(process.env.DEPLOY_HOST)) {
      throw new Error('Invalid DEPLOY_HOST format');
    }

    const userPattern = /^[a-z_][a-z0-9_-]{0,31}$/;
    if (!userPattern.test(process.env.DEPLOY_USER)) {
      throw new Error('Invalid DEPLOY_USER format');
    }

    this.log('Environment validation passed');
  }

  execSecure(command, args = [], options = {}) {
    const cmdName = command.split(' ')[0];
    
    if (!this.allowedCommands.has(cmdName)) {
      throw new Error(`Command not allowed: ${cmdName}`);
    }

    const fullCommand = args.length > 0 ? `${command} ${args.join(' ')}` : command;
    
    this.log(`Executing: ${this.sanitizeLog(fullCommand)}`);

    try {
      const result = execSync(fullCommand, {
        stdio: 'pipe',
        encoding: 'utf-8',
        maxBuffer: 10 * 1024 * 1024,
        timeout: 600000,
        ...options
      });
      
      return result;
    } catch (error) {
      this.log(`Command failed: ${this.sanitizeLog(error.message)}`, 'ERROR');
      throw error;
    }
  }

  validatePackageJson() {
    this.log('Validating package.json');
    
    const packagePath = path.join(process.cwd(), 'package.json');
    if (!fs.existsSync(packagePath)) {
      throw new Error('package.json not found');
    }

    const packageJson = JSON.parse(fs.readFileSync(packagePath, 'utf-8'));
    
    if (!packageJson.name || !packageJson.version) {
      throw new Error('package.json must contain name and version');
    }

    const namePattern = /^[@a-z0-9-_\/]+$/;
    if (!namePattern.test(packageJson.name)) {
      throw new Error('Invalid package name format');
    }

    const versionPattern = /^\d+\.\d+\.\d+(-[a-z0-9.]+)?$/;
    if (!versionPattern.test(packageJson.version)) {
      throw new Error('Invalid version format');
    }

    this.log(`Package: ${packageJson.name}@${packageJson.version}`);
    return packageJson;
  }

  installDependencies() {
    this.log('Installing dependencies');
    
    if (fs.existsSync('package-lock.json')) {
      this.execSecure('npm', ['ci', '--production=false', '--audit', '--fund=false']);
    } else {
      this.execSecure('npm', ['install', '--production=false', '--audit', '--fund=false']);
    }
    
    this.log('Dependencies installed');
  }

  generateSBOM() {
    this.log('Generating Software Bill of Materials (SBOM)');
    
    try {
      const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
      const packageLock = fs.existsSync('package-lock.json') 
        ? JSON.parse(fs.readFileSync('package-lock.json', 'utf-8'))
        : null;

      const sbom = {
        bomFormat: 'CycloneDX',
        specVersion: '1.4',
        version: 1,
        serialNumber: `urn:uuid:${crypto.randomUUID()}`,
        metadata: {
          timestamp: new Date().toISOString(),
          component: {
            type: 'application',
            name: packageJson.name,
            version: packageJson.version
          }
        },
        components: []
      };

      if (packageLock && packageLock.packages) {
        Object.entries(packageLock.packages).forEach(([pkgPath, pkg]) => {
          if (pkgPath === '') return;
          
          const name = pkgPath.replace('node_modules/', '');
          if (pkg.version) {
            sbom.components.push({
              type: 'library',
              name: name,
              version: pkg.version,
              purl: `pkg:npm/${encodeURIComponent(name)}@${pkg.version}`,
              hashes: pkg.integrity ? [{
                alg: pkg.integrity.split('-')[0],
                content: pkg.integrity.split('-')[1]
              }] : []
            });
          }
        });
      }

      fs.writeFileSync(this.sbomFile, JSON.stringify(sbom, null, 2));
      this.log(`SBOM generated: ${sbom.components.length} components`);
      
      return sbom;
    } catch (error) {
      this.log(`SBOM generation failed: ${error.message}`, 'ERROR');
      throw new Error('SBOM generation is required for deployment');
    }
  }

  runTests() {
    this.log('Running tests');
    
    const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    
    if (!packageJson.scripts || !packageJson.scripts.test) {
      this.log('No test script found, skipping tests', 'WARN');
      return;
    }

    this.execSecure('npm', ['test']);
    this.log('Tests passed');
  }

  buildApplication() {
    this.log('Building application');
    
    const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
    
    if (packageJson.scripts && packageJson.scripts.build) {
      this.execSecure('npm', ['run', 'build']);
    } else {
      this.log('No build script found, skipping build', 'WARN');
    }
    
    this.log('Build completed');
  }

  createDeploymentPackage() {
    this.log('Creating deployment package');
    
    const packageJson = this.validatePackageJson();
    const timestamp = Date.now();
    const packageName = `${packageJson.name.replace(/[@\/]/g, '-')}-${packageJson.version}-${timestamp}.tar.gz`;
    const packagePath = path.join(process.cwd(), packageName);

    const includePatterns = [
      'package.json',
      'package-lock.json',
      'node_modules',
      'dist',
      'build',
      'public',
      'src',
      'sbom.json'
    ];

    const existingPatterns = includePatterns.filter(pattern => 
      fs.existsSync(path.join(process.cwd(), pattern))
    );

    if (existingPatterns.length === 0) {
      throw new Error('No files to package');
    }

    this.execSecure('tar', [
      '-czf',
      packageName,
      ...existingPatterns
    ]);

    if (!fs.existsSync(packagePath)) {
      throw new Error('Package creation failed');
    }

    const stats = fs.statSync(packagePath);
    this.log(`Package created: ${packageName} (${(stats.size / 1024 / 1024).toFixed(2)} MB)`);
    
    return packageName;
  }

  deployToProduction(packageName) {
    this.log('Deploying to production');
    
    const deployHost = process.env.DEPLOY_HOST;
    const deployUser = process.env.DEPLOY_USER;
    const deployKeyPath = process.env.DEPLOY_KEY_PATH;
    const deployTarget = process.env.DEPLOY_TARGET;

    const sshOptions = [
      '-o', 'StrictHostKeyChecking=yes',
      '-o', 'UserKnownHostsFile=/root/.ssh/known_hosts',
      '-o', 'IdentitiesOnly=yes',
      '-o', 'ConnectTimeout=30',
      '-i', deployKeyPath
    ];

    const scpCommand = `scp ${sshOptions.join(' ')} ${packageName} ${deployUser}@${deployHost}:/tmp/`;
    
    this.log('Transferring package to server');
    execSync(scpCommand, { stdio: 'pipe' });

    const remoteCommands = [
      `cd /opt/app/${deployTarget}`,
      `tar -xzf /tmp/${packageName}`,
      `npm ci --production`,
      `pm2 restart ${deployTarget} || pm2 start ecosystem.config.js --env ${deployTarget}`,
      `rm /tmp/${packageName}`
    ].join(' && ');

    const sshCommand = `ssh ${sshOptions.join(' ')} ${deployUser}@${deployHost} "${remoteCommands}"`;
    
    this.log('Executing deployment commands on server');
    execSync(sshCommand, { stdio: 'pipe' });

    fs.unlinkSync(packageName);
    
    this.log('Deployment completed successfully');
  }

  run() {
    const startTime = Date.now();
    
    try {
      this.log('=== Starting CI/CD Pipeline ===');
      
      this.validateEnvironment();
      this.validatePackageJson();
      this.installDependencies();
      this.generateSBOM();
      this.runTests();
      this.buildApplication();
      
      const packageName = this.createDeploymentPackage();
      this.deployToProduction(packageName);
      
      const duration = ((Date.now() - startTime) / 1000).toFixed(2);
      this.log(`=== Pipeline completed successfully in ${duration}s ===`);
      
      process.exit(0);
    } catch (error) {
      this.log(`Pipeline failed: ${this.sanitizeLog(error.message)}`, 'ERROR');
      process.exit(1);
    }
  }
}

const pipeline = new SecureCICD();
pipeline.run();